) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Dumping data for table `trn_kontrak_paket`
--

INSERT INTO `trn_kontrak_paket` (`id`, `nama_paket`, `created_by`, `created_date`, `laporan`, `hasil`, `tugas_tanggung_jawab`) VALUES
(1, 'Perencanaan Program Hasil Terbaik Cepat (PHTC) Madrasah Tahap 3', 'agung', '2025-11-25', 'Laporan perencanaan teknis dan reviu desain menjadi:\r\n                        <ol>\r\n                            <li>Latar Belakang;</li>\r\n                            <li>Maksud dan Tujuan;</li>\r\n                            <li>Informasi Umum Lokasi Perencanaan;</li><li>Peta Sebaran Lokasi Pekerjaan;</li>\r\n                            <li>Jadwal Pelaksanaan Survei;</li>\r\n                            <li>Profil Sekolah/Madrasah;</li>\r\n                            <li>Formuli Identifikasi Kerusakan Bangunan;</li>\r\n                            <li>Pemetaan Citra Kawasan dan Topografi;</li>\r\n                            <li>Hasil Survei dan Penyelidikan Tanah (Sondir);</li>\r\n                            <li>Perencanaan Penanganan Massa Bangunan Dilengkapi Penanganan Kawasan (Vegetasi, Saluran Drainase dan Sirkulasi);</li>\r\n                            <li>Analisis Struktur dan Fondasi;</li>\r\n                            <li>Perbandingan RAB terbaru dengan RAB sebelumnya (Khusus Reviu);</li>\r\n                            <li>Perbandingan RAB dengan SHST Kabupaten/Kota;</li>\r\n                            <li>Analisis Jumlah Toilet dan Kebutuhan Air Bersih; dan</li>\r\n                            <li>Hasil Survei Harga Material Kabupaten/Kota</li>\r\n                        </ol>', '<ol class=\"sub-list\">\r\n                            <li>\r\n                                <strong><i>Detailed Engineering Design</i> (DED)</strong><br>\r\n                                <i>Detailed Engineering Design</i> (DED) meliputi:\r\n                                <ol class=\"sub-sub-list\">\r\n                                    <li>Gambar rencana massa bangunan gedung yang menunjukkan posisi massa bangunan</li>\r\n                                    <li>Gambar tampak bangunan yang menunjukkan pandangan ke empat sisi atau arah bangunan;</li>\r\n                                    <li>Gambar potongan bangunan secara melintang dan memanjang untuk menunjukkan secara garis besar penampang dan sistem struktur dan utilitas bangunan;</li>\r\n                                    <li>Pembuatan gambar tersebut di atas dibuat dalam skala 1:500 (satu banding lima ratus); 1:200 (satu banding dua ratus), 1:100 (satu banding seratus) atau yang memadai beserta ukuran untuk kejelasan informasi yang ingin dicapai;</li>\r\n                                    <li>Pengembangan arsitektur bangunan gedung berupa gambar rencana arsitektur yang menunjukkan hubungan antara lantai bangunan dan tata ruang luar terhadap garis sempadan bangunan, jalan dan ketentuan rencana tata kota lainnya;</li>\r\n                                    <li>Denah yang menunjukkan lantai-lantai dalam bangunan, susunan tata ruang dalam, koordinat bangunan, peil lantai dan ukuran-ukuran elemen bangunan serta jenis bahan yang digunakan;</li>\r\n                                    <li>Membuat pengembangan sistem struktur, berupa gambar potongan bangunan, secara melintang dan memanjang yang menjelaskan sistem struktur, ukuran dan peil elemen bangunan (fondasi, lantai, dinding, langit-langit dan atap) secara menyeluruh beserta uraian konsep dan perhitungannya; dan</li>\r\n                                    <li>Gambar DED meliputi: arsitektur, struktur, mekanikal, elektrikal, <i>plumbing</i> dan lansekap.</li>\r\n                                </ol>\r\n                            </li>\r\n                            Gambar DED dibuat dengan format <strong>A3 sebanyak 3 (tiga) eksemplar.</strong>\r\n                            <li>\r\n                                <strong>Rencana Anggaran Biaya (RAB)</strong><br>\r\n                                Rencanan Anggaran Biaya (RAB) pekerjaan konstruksi <i>Engineering Estimate</i> (EE) meliputi:\r\n                                <ol class=\"sub-sub-list\">\r\n                                    <li>Rincian Rencana Anggaran Biaya (RAB);</li>\r\n                                    <li>Rencana Anggaran Biaya (RAB);</li>\r\n                                    <li>Analisis Harga Satuan Pekerjaan (AHSP);</li>\r\n                                    <li>Daftar Harga Material dan Upah;</li>\r\n                                    <li>Referensi/Acuan Daftar Harga Bahan dan Upah (Pemda/Vendor);</li>\r\n                                    <li><i>Back Up</i> Volume/Data Beserta Rekapitulasi; dan</li>\r\n                                    <li>TKDN Rencana.</li>\r\n                                </ol>\r\n                            </li>\r\n                            RAB dibuat dengan format <strong>A4 sebanyak 3 (tiga) eksemplar.</strong>\r\n                            <li>\r\n                                <strong>Rencana Kerja dan Syarat-syarat (RKS)</strong><br>\r\n                                Rencana Kerja dan Syarat (RKS) yang meliputi:\r\n                                <ol class=\"sub-sub-list\">\r\n                                    <li>Persyaratan Umum;</li>\r\n                                    <li>Persyaratan Administratif; dan</li>\r\n                                    <li>Persyaratan teknis termasuk spesifikasi teknis;</li>\r\n                                </ol>\r\n                            </li>\r\n                            RKS dibuat dengan format <strong>A4 sebanyak 3 (tiga) eksemplar</strong>\r\n                        </ol>', 'Merupakan orang yang bertugas memimpin, mengarahkan, dan mengendalikan seluruh anggota tim kerja. Adapun tugas dan tanggungjawabnya mencakup hal-hal sebagai berikut:\r\n                        <ol class=\"sub-list\">\r\n                            <li>Melakukan survei penilaian kerusakan bangunan gedung madrasah;</li>\r\n                            <li>Melakukan analisis, perhitungan dan perencanaan arsitektur bangunan;</li>\r\n                            <li>Mengendalikan pengumpulan data perancangan arsitektur bangunan;</li>\r\n                            <li>Bertanggungjawab atas gambar perancangan secara keseluruhan;</li>\r\n                            <li>Menyusun spesifikasi teknis guna dokumen pelelangan;</li>\r\n                            <li>Menyusun laporan perancangan;</li>\r\n                            <li>Membuat analisa teknis dan persyaratan bahan (RKS) sesuai dengan spesifikasi teknis.</li>\r\n                            <li>Memeriksa dengan seksama hasil gambar kerja (DED) dan analisa/perhitungan perencanaan.</li>\r\n                            <li>Mengawasi semua tenaga/personil yang terlibat dalam pekerjaan perencanaan termasuk dalam survey lokasi, pengukuran dan pengumpulan data pekerjaan;</li>\r\n                            <li>Membuat jadwal kerja yang memuat <i>deadline</i> dan update progress pekerjaan;</li>\r\n                            <li>Bertanggungjawab atas ketepatan waktu pelaksanaan pekerjaan yang telah ditetapkan untuk pekerjaan survei, pengumpulan data primer, pengumpulan data sekunder, pengolahan dan penyajian laporan;</li>\r\n                            <li>Bertanggungjawab atas kebenaran, ketelitian dan kelengkapan laporan hasil pekerjaan perencanaan;</li>\r\n                            <li>Melakukan rapat atau koordinasi dengan pemberi tugas;</li>\r\n                            <li>Bersedia untuk melakukan revisi apabila ada perubahan gambar/desain pada saat pelaksanaan pekerjaan konstruksi.</li>\r\n                        </ol>'),
(2, 'Perencanaan SPPG Provinsi Riau', 'agung', '2025-11-25', NULL, NULL, NULL),
(3, 'Penyelidikan Tanah Sekolah Rakyat Provinsi Riau', 'agung', '2025-11-25', 'Laporan perencanaan teknis dan reviu desain menjadi:\r\na.	Latar Belakang;\r\nb.	Maksud dan Tujuan;\r\nc.	Informasi Umum Lokasi Penyelidikan Tanah;\r\nd.	Peta Sebaran Titik Penyelidikan Tanah;\r\ne.	Jadwal Pelaksanaan Penyelidikan Tanah;\r\nf.	Hasil Survei dan Penyelidikan Tanah (Sondir);\r\ng.	Hasil Pengeboran Tanah (Boaring);\r\nh.	Hasil Pengujian Laboratorium;\r\ni.	Analisis Hasil Penyelidikan Tanah dan Pengujian Laboratorium; dan\r\nj.	Kesmipulan dan Saran Hasil Penyelidikan Tanah.\r\n', 'Hasil penyelidikan geoteknik harus dilaporkan, didokumentasikan, dan disampaikan dalam format standar yang mencakup hal-hal sebagai berikut:\r\na.	Log bor (boring log) yang memuat deskripsi tanah, nilai N-SPT, klasifikasi tanah, elevasi muka air tanah, serta seluruh informasi yang diperoleh selama kegiatan penyelidikan.\r\nb.	Profil tanah yang menunjukkan stratigrafi tanah secara umum beserta nilai N-SPT pada setiap lapisan.\r\nc.	Ringkasan hasil pengujian laboratorium.\r\nd.	Hasil interpretasi dan rekomendasi parameter geoteknik yang diperlukan untuk keperluan desain.\r\ne.	Seluruh data lapangan, hasil pengujian laboratorium, serta dokumentasi pelaksanaan pekerjaan sebagai lampiran.\r\nf.	Laporan akhir penyelidikan tanah harus disusun secara lengkap dan ditandatangani oleh tenaga ahli geoteknik yang bersertifikat.', 'Merupakan orang yang bertugas memimpin, mengarahkan, dan mengendalikan seluruh anggota tim kerja. Adapun tugas dan tanggungjawabnya mencakup hal-hal sebagai berikut: \r\na.	Melaksanakan Persiapan Teknis dan Administratif;\r\nb.	Menyediakan dan Menjamin Kesiapan Peralatan serta Tenaga Ahli;\r\nc.	Melaksanakan Pengujian dan Pengambilan Data Lapangan;\r\nd.	Melakukan Pengujian Laboratorium Tanah;\r\ne.	Melakukan Analisis, Interpretasi, dan Penyusunan Rekomendasi Teknis;\r\nf.	Menyusun dan Menyerahkan Laporan Penyelidikan Tanah;\r\ng.	Menjamin Mutu Pekerjaan;\r\nh.	Mengawasi semua tenaga/personil yang terlibat dalam pekerjaan penyelidikan tanah; \r\ni.	Menyusun jadwal kerja yang mencakup target waktu serta pembaruan (update) progres pekerjaan;\r\nj.	Bertanggung jawab atas ketepatan waktu pelaksanaan pekerjaan, termasuk survei, pengumpulan data primer dan sekunder, pengolahan data, serta penyusunan laporan; \r\nk.	Bertanggung jawab atas kebenaran, ketelitian, dan kelengkapan laporan hasil pekerjaan; dan\r\nl.	Melaksanakan koordinasi atau rapat dengan pemberi tugas secara berkala dan sesuai kebutuhan.'),
(4, 'Perencanaan Teknis Pembangunan Sekolah Rakyat Kab. Kuantan Singingi Provinsi Riau', 'agung', '2025-12-01', NULL, NULL, NULL);

